        updateSecretKeyRequestConfig(secretKeyId = secretKeyId, secretKeyPatch = secretKeyPatch),
      requestOptions = requestOptions,
    )
  }

  private fun updateSecretKeyRequestConfig(
    secretKeyId: String,
    secretKeyPatch: SecretKeyPatch,
  ): RequestConfig {
    require(secretKeyId.isNotBlank()) {
      "Parameter `secretKeyId` is required when calling `updateSecretKey`."
    }
    return RequestConfig(
      method = RequestMethod.PATCH,
      path =
        "/agent-studio".split("/").filter { it.isNotBlank() } +
          listOf("1", "secret-keys", "$secretKeyId"),
      body = secretKeyPatch,
    )
  }

  /**
   * Helper: Forges a secured user token (JWT) for Agent Studio authenticated requests.
   *
   * @param secretKey The secret key to sign the token with.
   * @param secretKeyId The key ID to include in the JWT header (kid).
   * @param userId The user identifier to include as the subject (sub) claim.
   * @param expiresIn The token expiration in seconds from now. Defaults to 86400 (24 hours).
   * @return The signed JWT token.
   */
  public fun forgeSecuredUserToken(
    secretKey: String,
    secretKeyId: String,
    userId: String,
    expiresIn: Int = 24 * 3600,
  ): String {
    fun base64UrlEncode(data: ByteArray): String =
      kotlin.io.encoding.Base64.UrlSafe.encode(data).trimEnd('=')

    fun hmacSHA256(key: String, message: String): ByteArray {
      val hex = com.algolia.client.extensions.internal.encodeKeySHA256(key, message)
      return hex.chunked(2).map { it.toInt(16).toByte() }.toByteArray()
    }

    val now = kotlinx.datetime.Clock.System.now().epochSeconds
    val header =
      base64UrlEncode("""{"alg":"HS256","typ":"JWT","kid":"$secretKeyId"}""".encodeToByteArray())
    val payload =
      base64UrlEncode("""{"sub":"$userId","exp":${now + expiresIn}}""".encodeToByteArray())
    val signature = base64UrlEncode(hmacSHA256(secretKey, "$header.$payload"))

    return "$header.$payload.$signature"
  }
}
